const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const base = step.items.reduce(
        (sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0),
        0,
      );
      const premium = Math.ceil(base * 1.1) + 5;
      return { premium };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

