import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quoting - base premiums per item type (first insurance, new customer)
  it("should quote a sword for a new customer with first insurance", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("should quote an amulet for a new customer with first insurance", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it.todo("should quote a staff for a new customer with first insurance");
  it.todo("should quote a potion for a new customer with first insurance");

  // Quoting - components
  it.todo("should quote a single component (rune) at 25 G base");
  it.todo("should quote 3 alike components as a building block (60 G base, not 75 G)");
  it.todo("should quote 4 alike components as one block of 3 plus one single");

  // Quoting - risk surcharges
  it.todo("should add 50% surcharge for a cursed item");
  it.todo("should add 30% surcharge for a highly enchanted item (enchantment >= 5)");

  // Quoting - customer discounts/surcharges
  it.todo("should apply 20% loyalty discount for customer with >= 2 years");
  it.todo("should apply 15% subsequent-contract discount on the second quote in scenario");

  // Quoting - multiple items in one policy
  it.todo("should quote a policy of multiple items by summing their premiums");

  // Claims - basic
  it.todo("should pay out a simple claim minus 100 G deductible");
  it.todo("should reduce remaining cap by the payout amount");
  it.todo("should cap total payouts across multiple claims at 2x insurance sum");
  it.todo("should reimburse only 50% of damage for items with enchantment >= 8");
  it.todo("should fully reimburse damage for items made of dragon material");
});

