const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUM = 25;

const baseForItem = (item: Item): number =>
  BASE_PREMIUM[item.type] ?? COMPONENT_BASE_PREMIUM;

const roundUpInMHPCOFavor = (amount: number): number =>
  Math.ceil(Math.round(amount * 1e6) / 1e6);

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const base = step.items.reduce(
        (sum, item) => sum + baseForItem(item),
        0,
      );
      const premium = roundUpInMHPCOFavor(base * 1.1 + 5);
      return { premium };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

