    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: true },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 170 }] });
  });
  it("should add 30% surcharge for a highly enchanted item (enchantment >= 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 5, cursed: false },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 148 }] });
  });

  // Quoting - customer discounts/surcharges
  it("should apply 20% loyalty discount for customer with >= 2 years", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("should apply 15% subsequent-contract discount on the second quote in scenario", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
          ],
        },
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(result).toEqual({
      results: [{ premium: 115 }, { premium: 90 }],
    });
  });

  // Quoting - multiple items in one policy
  it.todo("should quote a policy of multiple items by summing their premiums");

  // Claims - basic
  it.todo("should pay out a simple claim minus 100 G deductible");
  it.todo("should reduce remaining cap by the payout amount");
  it.todo("should cap total payouts across multiple claims at 2x insurance sum");
  it.todo("should reimburse only 50% of damage for items with enchantment >= 8");
  it.todo("should fully reimburse damage for items made of dragon material");
});

